    while (matcher.find()) {
        String mention = matcher.group();
        // Remove @ symbol
        mentions.add(mention.substring(1));
    }
    // If mentions found, process them
    if (!mentions.isEmpty()) {
        // Replace @mentions with proper format
        for (String mention : mentions) {
            content = content.replace("@" + mention, "[at]" + mention + "[/at]");
