public static <V> void reverseRange(V[] arr, int from, int to) {
    if (arr == null || from >= to || from < 0 || to >= arr.length) {
        return;
    }
    while (from < to) {
        // Swap elements at from and to indices
        V temp = arr[from];
        arr[from] = arr[to];
        arr[to] = temp;
        from++;
        to--;
    }
}

